from keys import api_token_1, api_token_2, api_token_4, api_token_5, api_token_3, api_token_6, api_token_7,\
              api_token_8, api_token_9, api_token_10, api_token_11, api_token_12, api_token_13, api_token_14,\
              api_token_15, api_token_16, api_token_17
def get_players(top, region, players_dict, skipAnon, count=0, skip=0):
    tokens = [api_token_3, api_token_4, api_token_5, api_token_2, api_token_1, api_token_6, api_token_7,
              api_token_8, api_token_9, api_token_10, api_token_11, api_token_12, api_token_13, api_token_14,
              api_token_15, api_token_16, api_token_17]
    tokens_copy = tokens.copy()
    api_token = tokens.pop()
    while skip != top:
        query = '''{
           leaderboard{
             season(request:{leaderBoardDivision:%s}){
               players(take:100, skip:%s){
                 steamAccount{
                   isAnonymous
                   id
                   name
               }
               }}
           }
         }''' % (region, skip)
        headers = {
            "Content-Type": "application/json",
            "Accept": "application/json",
            "Accept-Encoding": "gzip, deflate, br, zstd",
            "Origin": "https://api.stratz.com",
            "Referer": "https://api.stratz.com/graphiql",
            "User-Agent": "STRATZ_API",
            "Authorization": f"Bearer {api_token}"
        }
        proxies = {
            'https': 'http://90gwi7LEfz:aKI0jgSViq@77.221.150.248:42037',
        }
        response = requests.post('https://api.stratz.com/graphql', json={"query": query}, headers=headers, proxies=proxies)
        if response.status_code == 200:
            data = json.loads(response.text)
            for player in data['data']['leaderboard']['season']['players']:

                if player['steamAccount']['id'] not in players_dict:
                    if skipAnon:
                        if (player['steamAccount']['isAnonymous'] is False):
                            players_dict[player['steamAccount']['id']] = player['steamAccount']['name']
                    else:
                        players_dict[player['steamAccount']['id']] = player['steamAccount']['name']
            skip += 100
        else:
            if tokens:
                api_token = tokens.pop()
                print(f'{response.status_code} меняю токен')
            else:
                tokens = tokens_copy
                api_token = tokens.pop()
                print('токены обновлены')
    return players_dict
